def test_surface_weighted_pca_exact_radii():
    nfp = 3
    major_radius = 2.3
    minor_radius = 0.5
    dimension = 10

    surface = SurfaceWeightedPCA(
        nfp=nfp,
        major_radius=major_radius,
        minor_radius=minor_radius,
        dimension=dimension,
        exact_radii=True,
    )
    surface2 = SurfaceWeightedPCA(
        nfp=nfp,
        major_radius=major_radius,
        minor_radius=minor_radius,
        dimension=dimension,
        exact_radii=False,
    )

    # Perturb controls so exact_radii enforcement is exercised on recompute.
    surface.x = np.ones_like(surface.x) * 0.6
    surface2.x = surface.x
    rz_surface = surface.to_RZFourier()
    rz_surface2 = surface2.to_RZFourier()
    print("Final major radius:", rz_surface.major_radius(), "minor radius:", rz_surface.minor_radius())

    np.testing.assert_allclose(
        rz_surface.major_radius(), major_radius, atol=1e-10, rtol=1e-12
    )
    np.testing.assert_allclose(
        rz_surface.minor_radius(), minor_radius, atol=1e-10, rtol=1e-12
    )
    # Surfaces should be identical up to the overall scale and the major radius
    np.testing.assert_allclose(
        rz_surface.x[1:] * rz_surface2.minor_radius() / rz_surface.minor_radius(),
        rz_surface2.x[1:],
    )


def test_surface_weighted_pca_with_vmec():
    vmec = Vmec(os.path.join(DATA_DIR, "input.vmec"))

    nfp = 3
    major_radius = 2.3
    minor_radius = 0.5
    dimension = 10

    pca_surface = SurfaceWeightedPCA(
        nfp=nfp,
        major_radius=major_radius,
        minor_radius=minor_radius,
        dimension=dimension,
    )
    vmec.boundary = pca_surface
    vmec.indata.nfp = nfp  # Vmec++ does not automatically get nfp from the boundary surface!

    vmec.run()
    # vmec.wout.save("wout_test_surface_pca_real_space_with_vmec.nc")
    np.testing.assert_equal(vmec.wout.nfp, nfp)
    np.testing.assert_allclose(vmec.wout.Rmajor_p, major_radius, rtol=0.02)
    np.testing.assert_allclose(vmec.wout.Aminor_p, minor_radius, rtol=0.006)
    print("iota:", list(vmec.wout.iotaf))
    np.testing.assert_allclose(vmec.wout.iotaf[0], 0.709064183361722)
    np.testing.assert_allclose(vmec.wout.iotaf[-1], 0.7343421267259607)